 * @return {number}
 */
function solve(nums) {
    const n = nums.length;
    if (n < 3) return 0;

    // The maximum number of special indices is floor((n - 2) / 2) * 2 + 1 or related to how peaks can be placed.
    // Since each peak i requires nums[i] > nums[i-1] and nums[i] > nums[i+1], and peaks must be separated by at least one non-peak,
    // the maximum number of peaks is around (n-1)/2.
    // However, since we only care about minimizing cost for the *maximum* number of peaks, 
    // and the maximum number of peaks is likely achieved by placing them as densely as possible, 
    // we can try to determine the maximum possible number of peaks first.

    // The structure of a peak is [low, high, low] or [low, high, high].
    // To maximize peaks, we want them at indices 1, 3, 5, ...
    // Maximum number of peaks is ceil((n-2)/2) or floor((n-1)/2).
    // For n=3, max peaks = 1 (index 1)
    // For n=4, max peaks = 1 (index 1 or 2)
    // For n=5, max peaks = 2 (indices 1 and 3)
    // For n=6, max peaks = 2 (indices 1 and 3, or 2 and 4)

    // Let's assume the maximum number of peaks is k_max. We want to find the minimum cost to achieve k_max peaks.
    // Due to the greedy nature and the local constraints, a dynamic programming approach or a carefully constructed greedy strategy is needed.

    // Observation: Increasing nums[i] only helps satisfy the conditions for i itself being a peak, 
    // or it might help satisfy conditions for i-1 or i+1 if they are potential peaks, 
    // but since we only increase values, we primarily aim to make the target peak large enough.

    // The structure suggests that the optimal configuration will likely involve setting peaks at indices 1, 3, 5, ... 
    // or 2, 4, 6, ...

    // Let's simplify the problem: If we fix the set of indices I we want to be peaks, the minimum cost is:
    // Cost = sum_{i in I} max(0, max(nums[i-1], nums[i+1]) + 1 - nums[i])
    // BUT, increasing nums[i] might also affect the requirement for i-2 or i+2 if they were peaks.
    // Since we only increase values, an increase at i only *helps* satisfy the condition at i-2 (if i-2 is a peak)
    // if i-2 needs nums[i-1] to be larger than nums[i-2], which is not the case.
    // An increase at i *might* affect i-2 if i-2 needs nums[i-1] > nums[i-2] and nums[i-1] is affected by i.
    // However, we only increase the chosen peak index.

    // If we choose a set of non-adjacent indices I = {i1, i2, ...} to be peaks, the cost for each peak i in I is determined locally, 
    // as long as no chosen peak i is adjacent to another chosen peak j (i.e., |i-j| > 1).
    // If |i-j| = 2, say i and i+2 are peaks.
    // For i: nums[i] > nums[i-1] and nums[i] > nums[i+1].
    // For i+2: nums[i+2] > nums[i+1] and nums[i+2] > nums[i+3].
    // The value nums[i+1] is constrained by both, but we only increase nums[i] or nums[i+2].
    // The constraints are independent if the set I is non-adjacent.

    // Maximum number of non-adjacent indices is achieved by selecting 1, 3, 5, ...
    const k_max = Math.ceil((n - 2) / 2);

    // We need to find the minimum cost to achieve k_max peaks. Since the structure is linear, DP is suitable.
    // DP[i][j][state]: Minimum cost considering prefix nums[0...i], achieving j peaks, where state describes the status of i and i-1.
    // State can be:
    // 0: i is not a peak, i-1 was not a peak.
    // 1: i is a peak, i-1 was not a peak. (i=1, 3, 5...)
    // 2: i is not a peak, i-1 was a peak. (This shouldn't happen if we aim for non-adjacent peaks)
    // 3: i is a peak, i-1 was a peak (Impossible if we enforce non-adjacency).

    // Since we aim for the maximum number of peaks, and adjacent peaks are impossible to achieve with a positive cost 
    // (as increasing one only helps the other slightly, but they compete for the value of the element between them), 
    // we assume the optimal set of peaks I is non-adjacent.

    // Let's use DP on indices 1 to n-2 (the possible peak locations).
    // dp[i][j]: minimum cost to have j peaks among indices {1, 2, ..., i}, where the choice at i is implicitly handled by the transition.

    // A simpler DP state, focusing on the index i (1 to n-2):
    // dp[i][j][0]: Min cost using prefix up to index i, achieving j peaks, where i is NOT a peak.
    // dp[i][j][1]: Min cost using prefix up to index i, achieving j peaks, where i IS a peak.

    // Initialize with Infinity.
    const INF = 1e18; 
    // dp size: (n) x (k_max + 1) x 2
    const dp = Array(n).fill(0).map(() => 
        Array(k_max + 1).fill(0).map(() => [INF, INF])
    );

    // Base Case: i=0 (not a valid peak index)
    // dp[0][0][0] = 0. We don't really need i=0, start DP from i=1.

    // Base Case: i=1 (first possible peak)
    // j=0: dp[1][0][0] = 0 (1 is not a peak)
    dp[1][0][0] = 0;

    // j=1: dp[1][1][1] = cost to make 1 a peak.
    let cost1 = Math.max(0, Math.max(nums[0], nums[2]) + 1 - nums[1]);
    dp[1][1][1] = cost1;

    // Iterate i from 2 to n-2 (possible peak indices)
    for (let i = 2; i <= n - 2; i++) {
        // Max number of peaks possible up to i is floor((i-1)/2) + 1. We cap it at k_max.
        const max_j = Math.min(k_max, Math.floor((i - 1) / 2) + 1);

        for (let j = 0; j <= max_j; j++) {
            // --- Calculate dp[i][j][0]: i is NOT a peak ---

            // Option 1: i-1 was NOT a peak. Cost is inherited from dp[i-1][j][0].
            dp[i][j][0] = Math.min(dp[i][j][0], dp[i-1][j][0]);

            // Option 2: i-1 WAS a peak. Cost is inherited from dp[i-1][j][1].
            dp[i][j][0] = Math.min(dp[i][j][0], dp[i-1][j][1]);


            // --- Calculate dp[i][j][1]: i IS a peak ---
            if (j > 0) {
                // To be a peak at i, i-1 MUST NOT be a peak (to maintain the maximum density structure).
                // Cost to make i a peak:
                let cost_i = Math.max(0, Math.max(nums[i-1], nums[i+1]) + 1 - nums[i]);

                // We transition from the state where i-1 was NOT a peak, having j-1 peaks previously.
                let prev_cost = dp[i-1][j-1][0];

                if (prev_cost !== INF) {
                    dp[i][j][1] = Math.min(dp[i][j][1], prev_cost + cost_i);
                }
            }
        }
    }

    // The maximum number of peaks achievable is k_max. We must find the minimum cost to achieve k_max peaks.
    // The final answer is min(dp[n-2][k_max][0], dp[n-2][k_max][1]).

    if (k_max === 0) {
        return 0;
    }

    // We check up to n-2 because n-1 is not a peak.
    const result = Math.min(dp[n-2][k_max][0], dp[n-2][k_max][1]);

    return result === INF ? 0 : result; // Should always find a solution if k_max > 0 and n >= 3
}

